from __future__ import annotations from pathlib import Path import xml.etree.ElementTree as ET import pytest
from aegrad.plotting.pvd import write_pvd
def _read_pvd(path: Path): tree = ET.parse(path) root = tree.getroot() coll = root.find("Collection") datasets = coll.findall("DataSet") return [(ds.get("timestep"), ds.get("file")) for ds in datasets]
def test_write_pvd_basic(tmp_path: Path): files = [tmp_path / f"frame_{i}.vts" for i in range(3)] # create dummy files for f in files: f.write_text("dummy")
times = [0.0, 0.1, 0.2] pvd_path = write_pvd(tmp_path, files, times)
assert pvd_path.exists() entries = _read_pvd(pvd_path) assert len(entries) == 3 for i, (t, f) in enumerate(entries): assert float(t) == pytest.approx(times[i]) # since use_relative_paths default True, expect filename to be the basename or relative assert f.endswith(f"frame_{i}.vts")
def test_write_pvd_mismatch_length(tmp_path: Path): files = [tmp_path / "a.vts", tmp_path / "b.vts"] for f in files: f.write_text("d") with pytest.raises(ValueError): write_pvd(tmp_path, files, [0.0])
def test_write_pvd_empty(tmp_path: Path): with pytest.raises(ValueError): write_pvd(tmp_path, [], [])
